sp_widget.client_script:
api.controller = function(spUtil) {
  var c = this;

  c.showEditView = false;
  c.selectedPatient = {};

  // Open Edit View & Fetch Native Form
  c.selectPatient = function(patient) {
    c.selectedPatient = patient; 
    c.showEditView = true; 

    // THE MAGIC: Fetch the native form widget for this specific patient
    spUtil.get('widget-form', {
      table: 'x_1954503_smartc_0_patient',
      sys_id: patient.sys_id,
      view: 'default', // You can change this if you made a specific 'portal' view
      hideRelatedLists: true // Keeps the UI clean
    }).then(function(response) {
      c.embeddedForm = response; // Store the fetched widget
    });
  };

  // Cancel and return to List
  c.backToList = function() {
    c.selectedPatient = {};
    c.embeddedForm = null; // Clear the embedded form
    c.showEditView = false; 
  };

  // Notice we deleted c.saveChanges()! The native form handles saving natively.
};

sp_widget.css:
/* --- Global Wrapper & Typography --- */
.sc-doc-wrapper {
  font-family: 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
  color: #1e293b;
  background-color: #f8fafc;
  padding: 30px;
}

/* --- The Main Panel (Card) --- */
.sc-doc-panel {
  background: #ffffff;
  border-radius: 12px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
  margin-bottom: 24px;
  overflow: hidden;
  border: 1px solid #eef2f6;
}

.sc-doc-panel-header {
  padding: 20px 24px;
  border-bottom: 1px solid #f1f5f9;
  background-color: #ffffff;
}

/* --- 1. TABLE BEAUTIFICATION (Keeping your awesome table) --- */
.sc-doc-table { width: 100%; border-collapse: collapse; }
.sc-doc-table th { background-color: #f8fafc; color: #64748b; font-size: 11px; font-weight: 700; text-transform: uppercase; padding: 16px 24px; border-bottom: 2px solid #f1f5f9; }
.sc-doc-table td { padding: 18px 24px; border-bottom: 1px solid #f1f5f9; font-size: 14px; }
.sc-doc-table tbody tr:hover { background-color: #fcfdfe; }

/* Badges */
.sc-doc-text-critical, .sc-doc-text-high, .sc-doc-text-moderate, .sc-doc-text-low { padding: 4px 12px; border-radius: 20px; font-size: 11px; font-weight: 700; display: inline-block; text-transform: uppercase; }
.sc-doc-text-critical { background-color: #fee2e2; color: #b91c1c; }
.sc-doc-text-high { background-color: #ffedd5; color: #9a3412; }
.sc-doc-text-moderate { background-color: #dbeafe; color: #1e40af; }
.sc-doc-text-low { background-color: #dcfce7; color: #15803d; }


/* --- 2. THE ULTIMATE REFERENCE FIELD FIX (Assigned Doctor/Nurse) --- */

/* Force all inputs to a clean height and remove overlap */
.sc-doc-wrapper .form-control,
.sc-doc-wrapper input,
.sc-doc-wrapper select {
  height: 38px !important; /* Slightly reduced height for elegance */
  border: 1px solid #e2e8f0 !important;
  border-radius: 6px !important;
  padding: 6px 12px !important;
  box-shadow: none !important;
  font-size: 13px !important;
}

/* Fix for the Reference Group (The container for the icon + input) */
.sc-doc-wrapper .input-group {
  display: flex !important;
  width: 100% !important;
  border: 1px solid #e2e8f0 !important; /* Outer border only */
  border-radius: 6px !important;
  overflow: hidden !important;
  background: #fff !important;
}

/* Reset internal elements of the input group */
.sc-doc-wrapper .input-group .form-control {
  border: none !important; /* Remove internal borders causing the overlap lines */
  margin: 0 !important;
  flex: 1 1 auto !important;
}

/* The "i" icon button area */
.sc-doc-wrapper .input-group-btn {
  display: flex !important;
  background-color: #f8fafc !important;
  border: none !important;
  padding: 0 !important;
  margin: 0 !important;
}

.sc-doc-wrapper .input-group-btn .btn {
  border: none !important;
  background: transparent !important;
  height: 38px !important;
  padding: 0 12px !important;
  color: #64748b !important;
  box-shadow: none !important;
}

/* The dropdown arrow area */
.sc-doc-wrapper .input-group-btn:last-child {
  border-left: 1px solid #f1f5f9 !important;
}

/* Hover/Focus effect for the whole box */
.sc-doc-wrapper .input-group:hover {
  border-color: #cbd5e1 !important;
}

.sc-doc-wrapper .input-group:focus-within {
  border-color: #0052cc !important;
  box-shadow: 0 0 0 3px rgba(0, 82, 204, 0.1) !important;
}

/* --- 3. SPACING & BUTTONS --- */
.sc-doc-panel-body { padding: 24px; }

.sc-doc-info-grid {
  display: flex; gap: 40px; background: #f1f5f9; padding: 15px 20px; border-radius: 8px; margin-bottom: 25px;
}

.sc-doc-wrapper label {
  font-weight: 600 !important; color: #475569 !important; font-size: 12px !important; margin-bottom: 6px !important;
}

/* Buttons */
.sc-doc-btn-link, .sc-doc-wrapper .btn-primary {
  background: #0052cc !important; border: none !important; color: #fff !important;
  padding: 8px 16px !important; border-radius: 6px !important; font-weight: 600 !important;
}

.sc-doc-btn-default, .sc-doc-wrapper .btn-default {
  background: #fff !important; border: 1px solid #e2e8f0 !important; color: #64748b !important;
  padding: 8px 16px !important; border-radius: 6px !important;
}

sp_widget.script:
(function() {
    var userId = gs.getUserID();


    var isDoctor = gs.hasRole('x_1954503_smartc_0.doctor');


    var isNurse = gs.hasRole('x_1954503_smartc_0.nurse');


    if (input && input.action == 'updatePatient') {
        var updateGR = new GlideRecord('x_1954503_smartc_0_patient');
        if (updateGR.get(input.patientUpdate.sys_id)) {
            updateGR.setValue('severity', input.patientUpdate.severity);
            updateGR.setValue('state', input.patientUpdate.state);
            updateGR.setValue('symptoms', input.patientUpdate.symptoms);

            updateGR.update();
        }
    }


    data.myPatients = [];
    var pGR = new GlideRecord('x_1954503_smartc_0_patient');


    if (isDoctor) {
        pGR.addQuery('assigned_doctor', userId);
    } else if (isNurse) {

        pGR.addQuery('u_assigned_nurse', userId); 
    } else {

        if (!gs.hasRole('admin')) {
            return; 
        }
    }

    pGR.orderByDesc('sys_created_on');
    pGR.query();

    while (pGR.next()) {
        data.myPatients.push({
            sys_id: pGR.getUniqueValue(),
            full_name: pGR.getValue('full_name') || 'Unknown',
            age: pGR.getValue('age') || '',
            department: pGR.getDisplayValue('medical_department') || '',
            state: pGR.getValue('state') || 'waiting',
            severity: pGR.getValue('severity') || 'low',
            symptoms: pGR.getValue('symptoms') || '',

            assigned_doctor: pGR.getDisplayValue('assigned_doctor'),
            assigned_nurse: pGR.getDisplayValue('assigned_nurse')
        });
    }
})();
